import React, { useEffect, useState } from 'react';
import { getSitios, deleteSitio, createSitio, updateSitio } from './services/culturaService';

function App() {
  const [sitios, setSitios] = useState([]);
  const [editandoId, setEditandoId] = useState(null);
  const [nuevoSitio, setNuevoSitio] = useState({ nombre: '', descripcion: '', ubicacion: '' });

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    const datos = await getSitios();
    setSitios(datos);
  };

  const handleChange = (e) => {
    setNuevoSitio({ ...nuevoSitio, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (editandoId) {
        await updateSitio(editandoId, nuevoSitio);
        setEditandoId(null);
    } else {
        await createSitio(nuevoSitio);
    }
    setNuevoSitio({ nombre: '', descripcion: '', ubicacion: '' });
    cargarDatos();
  };

  const prepararEdicion = (sitio) => {
    setEditandoId(sitio._id);
    setNuevoSitio({ nombre: sitio.nombre, descripcion: sitio.descripcion, ubicacion: sitio.ubicacion });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const eliminar = async (id) => {
    if(window.confirm('¿Desea eliminar este registro?')) {
      await deleteSitio(id);
      cargarDatos();
    }
  };

  return (
    <div className="bg-light min-vh-100">
      {/* Navbar con Bootstrap */}
      <nav className="navbar navbar-dark bg-primary shadow-sm mb-5">
        <div className="container">
          <span className="navbar-brand mb-0 h1">🏛️ Cultura La Paz</span>
        </div>
      </nav>

      <div className="container">
        <div className="row justify-content-center">
          
          {/* SECCIÓN DEL FORMULARIO */}
          <div className="col-md-6 mb-5">
            <div className="card shadow-sm border-0">
              <div className="card-body p-4">
                <h4 className="card-title text-primary text-center mb-4">
                  {editandoId ? 'Editar Sitio Cultural' : 'Registrar Nuevo Sitio'}
                </h4>
                <form onSubmit={handleSubmit}>
                  <div className="mb-3">
                    <label className="form-label fw-bold">Nombre</label>
                    <input type="text" className="form-control" name="nombre" placeholder="Nombre del sitio" value={nuevoSitio.nombre} onChange={handleChange} required />
                  </div>
                  <div className="mb-3">
                    <label className="form-label fw-bold">Descripción</label>
                    <textarea className="form-control" name="descripcion" rows="3" placeholder="Reseña informativa" value={nuevoSitio.descripcion} onChange={handleChange} required></textarea>
                  </div>
                  <div className="mb-3">
                    <label className="form-label fw-bold">Ubicación</label>
                    <input type="text" className="form-control" name="ubicacion" placeholder="Dirección exacta" value={nuevoSitio.ubicacion} onChange={handleChange} required />
                  </div>
                  <button type="submit" className={`btn w-100 ${editandoId ? 'btn-warning' : 'btn-success'}`}>
                    {editandoId ? 'Actualizar Información' : 'Guardar en Sistema'}
                  </button>
                  {editandoId && (
                    <button type="button" className="btn btn-link w-100 mt-2 text-muted" onClick={() => {setEditandoId(null); setNuevoSitio({nombre:'', descripcion:'', ubicacion:''})}}>
                      Cancelar Edición
                    </button>
                  )}
                </form>
              </div>
            </div>
          </div>

          {/* SECCIÓN DE LAS TARJETAS */}
          <div className="col-12">
            <h3 className="mb-4 border-bottom pb-2">Sitios Registrados</h3>
            <div className="row">
              {sitios.map(sitio => (
                <div key={sitio._id} className="col-md-4 mb-4">
                  <div className="card h-100 shadow-sm border-start border-primary border-4">
                    <div className="card-body">
                      <h5 className="card-title text-dark">{sitio.nombre}</h5>
                      <p className="card-text text-secondary">{sitio.descripcion}</p>
                      <p className="small mb-3"><strong>📍 Ubicación:</strong> {sitio.ubicacion}</p>
                    </div>
                    <div className="card-footer bg-white border-top-0 d-flex gap-2 pb-3">
                      <button onClick={() => prepararEdicion(sitio)} className="btn btn-outline-primary btn-sm flex-grow-1">Editar</button>
                      <button onClick={() => eliminar(sitio._id)} className="btn btn-outline-danger btn-sm flex-grow-1">Eliminar</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

export default App;
